import dataclasses, datetime
from typing import List

@dataclasses.dataclass
class DailyUtilisationReport:
    commitment_id: str
    period_start: datetime.date
    period_end: datetime.date
    committed_usd: float
    spent_to_date_usd: float
    days_elapsed: int
    total_days: int

    @property
    def pace_pct(self) -> float:
        if self.days_elapsed == 0:
            return 0.0
        expected = self.committed_usd * (self.days_elapsed / self.total_days)
        return self.spent_to_date_usd / expected if expected > 0 else 0.0

    @property
    def projected_annual_spend(self) -> float:
        if self.days_elapsed == 0:
            return 0.0
        daily_rate = self.spent_to_date_usd / self.days_elapsed
        return daily_rate * self.total_days

    @property
    def projected_true_up(self) -> float:
        shortfall = self.committed_usd - self.projected_annual_spend
        return max(shortfall, 0.0)

    def status_emoji(self) -> str:
        p = self.pace_pct
        if p >= 0.95:
            return "✅ on-track"
        if p >= 0.80:
            return "🟡 watch"
        return "🔴 lagging"

    def format_slack_message(self) -> str:
        return (
            f"*{self.commitment_id}* — {self.status_emoji()}\n"
            f"  Spent: ${self.spent_to_date_usd:,.0f} / ${self.committed_usd:,.0f} "
            f"({self.pace_pct:.0%} of pace)\n"
            f"  Projected spend: ${self.projected_annual_spend:,.0f}  "
            f"  Projected true-up: ${self.projected_true_up:,.0f}"
        )


def post_daily_digest(reports: List[DailyUtilisationReport], webhook_url: str) -> None:
    import urllib.request, json
    lines = ["*Daily Commitment Utilisation Digest*"] + [r.format_slack_message() for r in reports]
    payload = json.dumps({"text": "\n".join(lines)}).encode()
    req = urllib.request.Request(webhook_url, data=payload, headers={"Content-Type": "application/json"})
    urllib.request.urlopen(req, timeout=10)

@dataclasses.dataclass
class TrueUpReserve:
    committed_usd: float
    reserve_pct: float  # e.g. 0.10 for 10 %

    @property
    def reserve_amount(self) -> float:
        return self.committed_usd * self.reserve_pct

    @property
    def total_budget_required(self) -> float:
        return self.committed_usd + self.reserve_amount

    def surplus_after_true_up(self, actual_true_up_usd: float) -> float:
        """Positive = unused reserve returned to budget pool."""
        return self.reserve_amount - actual_true_up_usd

@dataclasses.dataclass
class CommitmentPool:
    pool_id: str
    provider: str
    model_family: str
    committed_usd: float
    spent_to_date_usd: float
    months_elapsed: int
    total_months: int = 12

    @property
    def utilisation_pct(self) -> float:
        expected = self.committed_usd * (self.months_elapsed / self.total_months)
        return self.spent_to_date_usd / expected if expected > 0 else 0.0

    @property
    def monthly_surplus(self) -> float:
        monthly_commitment = self.committed_usd / self.total_months
        monthly_spend = self.spent_to_date_usd / max(self.months_elapsed, 1)
        return monthly_commitment - monthly_spend  # positive = under-utilised


def rebalance_recommendations(pools: list["CommitmentPool"]) -> list[str]:
    over = [p for p in pools if p.utilisation_pct > 1.05]
    under = [p for p in pools if p.utilisation_pct < 0.80]
    recs = []
    for src in over:
        for dst in under:
            if src.provider == dst.provider:
                recs.append(
                    f"Shift workloads from {src.pool_id} (over-committed) "
                    f"to {dst.pool_id} (under-utilised) — same provider, zero migration cost."
                )
    return recs
